from urllib.parse import urlparse, urljoin


def is_safe_url(target: str, host_url: str, allowed_schemes=("http", "https")) -> bool:
    if not target:
        return False
    ref_url = urlparse(host_url)
    test_url = urlparse(urljoin(host_url, target))
    return (
        test_url.scheme in allowed_schemes
        and ref_url.netloc == test_url.netloc
    )


def get_redirect_target(request_args=None, request_form=None, request_headers=None, host_url="") -> str | None:
    request_args = request_args or {}
    request_form = request_form or {}
    request_headers = request_headers or {}

